    <script>
        document.addEventListener('DOMContentLoaded', function() {
            function hasTrackAndList(root) {
                if (!root) return false;
                return !!(root.querySelector('.splide__track') && root.querySelector('.splide__list'));
            }

            function safeInit(selector, options) {
                var root = document.querySelector(selector);
                if (!root) return null;
                if (!hasTrackAndList(root)) {
                    console.warn('[splide] Skipping init for "' + selector + '" — missing track/list.');
                    return null;
                }
                var instance = new Splide(root, options);
                instance.mount();
                return instance;
            }

            var splideYears = safeInit('.splide-years', {
                type: 'loop',
                perPage: 5,
                perMove: 1,
                arrows: true,
                pagination: false,
                breakpoints: {
                    1024: {
                        perPage: 3,
                        arrows: true
                    },
                    640: {
                        perPage: 1,
                        arrows: true
                    },
                },
            });

            // Posters Splide: 3 per page
            safeInit('.splide-posters', {
                type: 'slide',
                perPage: 3,
                perMove: 1,
                autoplay: true,
                interval: 3000,
                pagination: false,
                gap: '1rem',
                breakpoints: {
                    1024: {
                        perPage: 2
                    },
                    640: {
                        perPage: 1
                    },
                },
            });

            // Lazy loading images
            function loadImages(container) {
                var lazyImages = container.querySelectorAll('.lazy-image:not(.loaded)');
                lazyImages.forEach(function(img) {
                    if (img.dataset.src) {
                        img.src = img.dataset.src;
                        img.classList.add('loaded');
                        img.style.opacity = '0';
                        img.onload = function() {
                            img.style.transition = 'opacity 0.3s';
                            img.style.opacity = '1';
                        };
                    }
                });
            }

            // Switch between main sections (posters/convocatorias)
            function switchMainSection(section) {
                var postersContent = document.getElementById('postersContent');
                var convocatoriasContent = document.getElementById('convocatoriasContent');
                var yearItems = document.querySelectorAll('.year-item');

                if (section === 'posters') {
                    postersContent.classList.remove('hidden');
                    convocatoriasContent.classList.add('hidden');
                    // Remove active state from all years
                    yearItems.forEach(function(item) {
                        item.style.color = '';
                    });
                } else {
                    postersContent.classList.add('hidden');
                    convocatoriasContent.classList.remove('hidden');
                }
            }

            // Switch convocatoria based on year
            function switchConvocatoria(year) {
                switchMainSection('convocatorias');

                // Update active year styling
                var yearItems = document.querySelectorAll('.year-item');
                yearItems.forEach(function(item) {
                    if (item.getAttribute('data-year') === year) {
                        item.style.color = '#008fbd';
                    } else {
                        item.style.color = '';
                    }
                });
                var items = document.querySelectorAll('.convocatoria-item');
                items.forEach(function(item) {
                    if (item.dataset.year == year) {
                        item.classList.remove('hidden');
                        item.classList.add('active');
                        // Load images for this year
                        setTimeout(function() {
                            loadImages(item);
                        }, 100);
                    } else {
                        item.classList.add('hidden');
                        item.classList.remove('active');
                    }
                });
            }

            // Click handler for year items (independent of Splide)
            var yearItems = document.querySelectorAll('.year-item');
            yearItems.forEach(function(yearItem) {
                yearItem.addEventListener('click', function() {
                    var year = yearItem.getAttribute('data-year');
                    switchConvocatoria(year);
                });
            });

            // Click handler for posterSection icon
            var posterSection = document.getElementById('posterSection');
            if (posterSection) {
                posterSection.addEventListener('click', function() {
                    switchMainSection('posters');
                });
            }
        });
    </script>
</section>

